class User { String name; User(String n) { this.name = n; } }

static void changeName(User u)  { u.name = "Bob"; }        // mutates the object
static void reassign(User u)     { u = new User("Bob"); }  // reassigns local ref

public static void main(String[] args) {
  User user = new User("Ada");
  changeName(user);
  System.out.println(user.name);   // Bob — the object was mutated

  User other = new User("Ada");
  reassign(other);
  System.out.println(other.name);  // Ada — the reassignment only affected the local copy
}

// Both parameters received a COPY of the reference.
// A copy pointing to the same object → mutating works.
// A copy is a copy → reassigning doesn't touch the caller's variable.

// File: CoreJavaDemo.java
// Compile: javac CoreJavaDemo.java
// Run:     java CoreJavaDemo

public class CoreJavaDemo {
  static class Money {
    long paise;
    Money(long p) { this.paise = p; }

    @Override public boolean equals(Object o) {
      if (this == o) return true;
      if (!(o instanceof Money)) return false;
      return paise == ((Money) o).paise;
    }
    @Override public int hashCode() { return Long.hashCode(paise); }
    @Override public String toString() { return "₹" + paise / 100.0; }
  }

  public static void main(String[] args) {
    // --- Primitives ---
    int a = 5, b = 5;
    System.out.println(a == b);          // true — comparing values

    // --- Objects and identity vs equality ---
    Money m1 = new Money(1000);
    Money m2 = new Money(1000);
    System.out.println(m1 == m2);        // false — different objects
    System.out.println(m1.equals(m2));   // true — same content

    // --- Wrapper caching (a famous gotcha) ---
    Integer x = 100, y = 100;
    System.out.println(x == y);          // true — Integer cache -128..127
    Integer p = 200, q = 200;
    System.out.println(p == q);          // false — outside cache

    // --- Pass-by-value with objects ---
    Money account = new Money(500);
    deposit(account, 100);
    System.out.println(account);         // ₹6.0 — mutated

    Money frozen = new Money(500);
    replace(frozen);
    System.out.println(frozen);          // ₹5.0 — reassignment didn't leak out

    // --- String immutability ---
    String s = "hello";
    s.concat(" world");                  // returns a new String; original unchanged
    System.out.println(s);               // hello
    s = s + " world";                    // now s points to a NEW String
    System.out.println(s);               // hello world
  }

  static void deposit(Money m, long amount) { m.paise += amount * 100; }
  static void replace(Money m) { m = new Money(9999); }   // no effect outside
}

// Expected output:
//   true
//   false
//   true
//   true
//   false
//   ₹6.0
//   ₹5.0
//   hello
//   hello world
